class Solution:
    def numberOfRounds(self, loginTime, logoutTime):
        def mins(s):
            return int(s[:2]) * 60 + int(s[3:])
        start = mins(loginTime)
        end = mins(logoutTime)
        if end < start:
            end += 24 * 60
        count = 0
        for b in range(0, 48 * 60, 15):
            if b >= start and b + 15 <= end:
                count += 1
        return count

