class Solution:
    def numberOfRounds(self, loginTime, logoutTime):
        def mins(s):
            return int(s[:2]) * 60 + int(s[3:])
        start = mins(loginTime)
        end = mins(logoutTime)
        if end < start:
            end += 24 * 60
        up = (start + 14) // 15
        down = end // 15
        return max(0, down - up)

