var numberOfRounds = function(loginTime, logoutTime) {
    const mins = s => parseInt(s.slice(0, 2), 10) * 60 + parseInt(s.slice(3), 10);
    let start = mins(loginTime);
    let end = mins(logoutTime);
    if (end < start) end += 24 * 60;
    const up = Math.floor((start + 14) / 15);
    const down = Math.floor(end / 15);
    return Math.max(0, down - up);
};
